// ============================================================
// SÉQUENCEUR MEPA V6.2 — Init liste 27 WP
// Retourne 27 items (un par WP) en ordre de stratification.
// n8n (executionOrder=v1) traite les items séquentiellement
// dans Execute Workflow — un WP à la fois.
// ============================================================
"use strict";
const MEPA_CONFIG_DIR = $env.MEPA_SCRIPTS_DIR
  ? $env.MEPA_SCRIPTS_DIR.replace('/scripts', '/config')
  : '/data/mepa/config';

const WP_LIST = [{"wp_id": "WP-I10-1", "fiche": "WP-I10-1_Rwanda_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-C1-1", "fiche": "WP-C1-1_Haiti_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-F10-1", "fiche": "WP-F10-1_CommuneParis_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-F1-1", "fiche": "WP-F1-1_RomeIIIe_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F2-1", "fiche": "WP-F2-1_RomeTardive_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F3-1", "fiche": "WP-F3-1_MayaClassique_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F4-1", "fiche": "WP-F4-1_EgypteAncienne_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F5-1", "fiche": "WP-F5-1_VeniseDéclin_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F6-1", "fiche": "WP-F6-1_EmpireOttoman_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F7-1", "fiche": "WP-F7-1_RevolutionHaitienne_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F8-1", "fiche": "WP-F8-1_FranceRevolutionnaire_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F9-1", "fiche": "WP-F9-1_AngleterreStabilite_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-I1-1", "fiche": "WP-I1-1_AngleterreIndustrielle_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I2-1", "fiche": "WP-I2-1_Russie1917_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I3-1", "fiche": "WP-I3-1_JaponMeijiGuerre_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I4-1", "fiche": "WP-I4-1_AllemagneNazie_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I5-1", "fiche": "WP-I5-1_EspagneGuerreCivile_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I6-1", "fiche": "WP-I6-1_Tiananmen_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I7-1", "fiche": "WP-I7-1_URSS_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I8-1", "fiche": "WP-I8-1_ChineDeng_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I9-1", "fiche": "WP-I9-1_Singapour_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C2-1", "fiche": "WP-C2-1_Egypte2011_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C3-1", "fiche": "WP-C3-1_Argentine_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C4-1", "fiche": "WP-C4-1_Liban_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C5-1", "fiche": "WP-C5-1_Iran_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C6-1", "fiche": "WP-C6-1_ChineXi_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-T1-1", "fiche": "WP-T1-1_GuerreSecession_v62.json", "phase": "TRANSITIONS", "zone": "ZONE DE STRESS"}];

return WP_LIST.map((wp, idx) => ({
  json: {
    seq_index:          idx + 1,
    seq_total:          WP_LIST.length,
    wp_id:              wp.wp_id,
    fiche_path:         `${MEPA_CONFIG_DIR}/${wp.fiche}`,
    phase:              wp.phase,
    zone_stratification:wp.zone,
    seq_started_at:     new Date().toISOString()
  }
}));

// ============================================================
// SÉQUENCEUR — Log résultat + triage
// Lit la sortie de WF2, classe le résultat, écrit dans
// outputs/multipass_log.json (append atomique via fichier lock).
// ============================================================
"use strict";
const fs = require('fs');
const data = $input.item.json;

const BASE    = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';
const LOG_PATH = `${BASE}/multipass_log.json`;

// Lire le log existant
let log = [];
try { log = JSON.parse(fs.readFileSync(LOG_PATH, 'utf8')); } catch(_) {}

// Construire l'entrée de log
const result = data?.passeport_compact || data;
const statut = result?.statut_cert || data?.statut_certification || 'INCONNU';
const is_nc_bloquant = data?.motif === 'DONNEES_INSUFFISANTES'
  || data?.status === 'NC_BLOQUANT'
  || statut === 'NC_BLOQUANT';
const is_fatal = is_nc_bloquant
  || (data?.exitCode && data.exitCode !== 0 && !data?.wp_id);

const entry = {
  seq_index:   data.seq_index ?? null,
  wp_id:       result?.wp_id  || data?.wp_id || '?',
  phase:       data.phase     || '?',
  statut_cert: statut,
  cci:         result?.CCI    ?? null,
  robustesse:  result?.robustesse ?? null,
  concordance: result?.concordant ?? null,
  traj_diagn:  result?.traj_diagn ?? null,
  traj_attendue: result?.traj_attendue ?? null,
  is_fatal,
  timestamp:   new Date().toISOString()
};

log.push(entry);
fs.writeFileSync(LOG_PATH, JSON.stringify(log, null, 2), 'utf8');

return {
  json: {
    ...data,
    log_entry: entry,
    is_fatal,
    log_path: LOG_PATH,
    seq_progress: `${data.seq_index ?? '?'}/${data.seq_total ?? 27}`,
    message: `[SEQ ${data.seq_index ?? '?'}/${data.seq_total ?? 27}] ${entry.wp_id} → ${statut}`
  }
};

// ============================================================
// SÉQUENCEUR — Alerte fatale (NC bloquant ou erreur runner)
// Écrit dans outputs/sequencer_alerts.json et s'arrête.
// ============================================================
"use strict";
const fs = require('fs');
const data = $input.item.json;
const BASE  = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';
const ALERT_PATH = `${BASE}/sequencer_alerts.json`;

let alerts = [];
try { alerts = JSON.parse(fs.readFileSync(ALERT_PATH, 'utf8')); } catch(_) {}

alerts.push({
  wp_id:     data.wp_id || '?',
  motif:     data.motif || data.status || 'ERREUR_FATALE',
  detail:    data.message || data.action_requise || '',
  timestamp: new Date().toISOString()
});
fs.writeFileSync(ALERT_PATH, JSON.stringify(alerts, null, 2), 'utf8');

// Lancer une erreur pour arrêter le workflow n8n
throw new Error(`[SÉQUENCEUR STOP] ${data.wp_id} — ${data.motif || 'ERREUR_FATALE'}. Voir ${ALERT_PATH}`);

// ============================================================
// SÉQUENCEUR — Synthèse finale (appelé après le dernier WP)
// Lit multipass_log.json et produit un résumé terminal.
// ============================================================
"use strict";
const fs = require('fs');
const data = $input.item.json;
const BASE = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';
const LOG_PATH = `${BASE}/multipass_log.json`;

let log = [];
try { log = JSON.parse(fs.readFileSync(LOG_PATH, 'utf8')); } catch(_) {}

const total       = log.length;
const certifies   = log.filter(e => e.statut_cert === 'WP_CERTIFIE').length;
const exploratoires = log.filter(e => e.statut_cert === 'WP_EXPLORATOIRE').length;
const erreurs     = log.filter(e => e.is_fatal).length;
const cci_values  = log.filter(e => e.cci !== null).map(e => e.cci);
const cci_moyen   = cci_values.length
  ? (cci_values.reduce((a,b)=>a+b,0)/cci_values.length).toFixed(3)
  : null;

const synthese = {
  generated_at: new Date().toISOString(),
  corpus: { total, certifies, exploratoires, erreurs },
  cci_moyen,
  detail: log
};

fs.writeFileSync(LOG_PATH, JSON.stringify(synthese, null, 2), 'utf8');

return {
  json: {
    status: 'SEQUENCEUR_TERMINE',
    corpus: synthese.corpus,
    cci_moyen,
    log_path: LOG_PATH,
    message: `[SÉQUENCEUR COMPLET] ${total} WP traités — ${certifies} certifiés, ${exploratoires} exploratoires, ${erreurs} erreurs`
  }
};
